import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { addLead } from "../../api/leadApi";
import LeadForm from "./LeadForm";

function AddLead() {
  const navigate = useNavigate();
  const [saving, setSaving] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    contact_number: "",
    email: "",
    lead_source: "",
    interest_level: "",
    status: "new",
  });

  const handleChange = (event) => {
    const { name, value } = event.target;
    setFormData((current) => ({ ...current, [name]: value }));
  };

  const submit = async (event) => {
    event.preventDefault();
    setSaving(true);

    try {
      await addLead({
        name: formData.name,
        contact_number: formData.contact_number,
        email: formData.email,
        lead_source: formData.lead_source,
        interest_level: formData.interest_level,
      });
      alert("Lead added successfully");
      navigate("/leads");
    } catch (err) {
      const message = err.response?.data?.message || err.response?.data?.errors?.[0] || err.message || "Error adding lead";
      alert(message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <LeadForm
      title="Add Lead"
      subtitle="Create a new CRM record with the same cleaner premium layout used across the rest of the management pages."
      modeLabel="New CRM Entry"
      form={formData}
      onChange={handleChange}
      onSubmit={submit}
      saving={saving}
      submitLabel="Save Lead"
      onCancel={() => navigate("/leads")}
    />
  );
}

export default AddLead;
